// Collect all generated content into one structured output
const items = $input.all();

const parseResponse = (item) => {
  try {
    return item.json?.choices?.[0]?.message?.content || '';
  } catch(e) {
    return '';
  }
};

// Items arrive in order: tweets, thread, linkedin, newsletter
const twitterPosts = parseResponse(items[0] || {});
const twitterThread = parseResponse(items[1] || {});
const linkedinPost = parseResponse(items[2] || {});
const newsletterSection = parseResponse(items[3] || {});

const timestamp = new Date().toISOString();
const dateStr = timestamp.split('T')[0];

return [{
  json: {
    title: 'Content Repurpose Batch',
    date: dateStr,
    twitterPosts: twitterPosts,
    twitterThread: twitterThread,
    linkedinPost: linkedinPost,
    newsletterSection: newsletterSection,
    status: 'PENDING_REVIEW',
    generatedAt: timestamp,
    platformCount: 4,
    contentPieces: '5 tweets + 1 thread + 1 linkedin + 1 newsletter'
  }
}];

